use std::ffi::OsStr;
use std::fs;
use std::path::{Path, PathBuf};
use std::process::Command;

use super::adapter::{BuildAdapter, detect_build_adapter};
use crate::config::{DEFAULT_JS_APP_ROOT, TakoToml};
use typegen_path::resolve_declaration_path;
pub(crate) use typegen_path::{generated_declaration_parent_dirs, is_generated_declaration_path};

mod typegen_path;

const TAKO_DTS_HEADER: &str = r#"/* prettier-ignore-start */
/* eslint-disable */
/* oxlint-disable */
/**
 * AUTO-GENERATED BY TAKO — DO NOT EDIT
 *
 * Regenerated by the Tako CLI on init, dev, deploy, `tako generate`, and
 * secrets changes. Manual edits will be overwritten on the next run.
 */

import "tako.sh";

"#;

const JS_MODULE_EXTS: &[&str] = &[".ts", ".tsx", ".js", ".mjs", ".mts"];

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
pub struct JsGeneratedFilesResult {
    pub wrote_declarations: bool,
    pub wrote_scaffolds: bool,
}

/// Read the declared environment names from `tako.toml`'s `[envs.*]` tables.
///
/// "development" and "production" are always included as base environments
/// (so apps running under `tako dev` always typecheck). Any additional envs
/// declared in `tako.toml` are merged in, sorted, deduplicated.
fn read_env_names(project_dir: &Path) -> Vec<String> {
    let mut names: std::collections::BTreeSet<String> = ["development", "production"]
        .iter()
        .map(|s| s.to_string())
        .collect();

    for candidate in ["tako.toml"] {
        let path = project_dir.join(candidate);
        let Ok(content) = fs::read_to_string(&path) else {
            continue;
        };
        let Ok(parsed): Result<toml::Value, _> = toml::from_str(&content) else {
            continue;
        };
        if let Some(envs) = parsed.get("envs").and_then(|v| v.as_table()) {
            for name in envs.keys() {
                names.insert(name.clone());
            }
        }
        break;
    }

    names.into_iter().collect()
}

/// Read secret names from `.tako/secrets.json` for the "development" environment.
///
/// Falls back to all secret names across all environments if no development
/// environment exists. Returns an empty vec if the file doesn't exist or is
/// malformed.
fn read_secret_names(project_dir: &Path) -> Vec<String> {
    let secrets_path = project_dir.join(".tako").join("secrets.json");
    let Ok(content) = fs::read_to_string(&secrets_path) else {
        return Vec::new();
    };

    let Ok(parsed): Result<serde_json::Value, _> = serde_json::from_str(&content) else {
        return Vec::new();
    };

    let Some(envs) = parsed.as_object() else {
        return Vec::new();
    };

    if let Some(dev) = envs.get("development")
        && let Some(secrets) = dev.get("secrets").and_then(|s| s.as_object())
    {
        let mut names: Vec<String> = secrets.keys().cloned().collect();
        names.sort();
        return names;
    }

    let mut names_set = std::collections::BTreeSet::new();
    for env_value in envs.values() {
        if let Some(secrets) = env_value.get("secrets").and_then(|s| s.as_object()) {
            for name in secrets.keys() {
                names_set.insert(name.clone());
            }
        }
    }
    names_set.into_iter().collect()
}

fn ts_property_name(name: &str) -> String {
    let mut chars = name.chars();
    let Some(first) = chars.next() else {
        return "\"\"".to_string();
    };
    let first_ok = first == '_' || first == '$' || first.is_ascii_alphabetic();
    let rest_ok = chars.all(|ch| ch == '_' || ch == '$' || ch.is_ascii_alphanumeric());
    if first_ok && rest_ok {
        name.to_string()
    } else {
        format!("{name:?}")
    }
}

fn ts_secret_accessor(name: &str) -> String {
    let property = ts_property_name(name);
    if property == name {
        format!("tako.secrets.{property}")
    } else {
        format!("tako.secrets[{property}]")
    }
}

fn secret_example_binding(name: &str) -> String {
    let mut out = String::new();
    for (index, part) in name.split('_').filter(|part| !part.is_empty()).enumerate() {
        let lower = part.to_ascii_lowercase();
        if index == 0 {
            out.push_str(&lower);
        } else {
            let mut chars = lower.chars();
            if let Some(first) = chars.next() {
                out.push(first.to_ascii_uppercase());
                out.extend(chars);
            }
        }
    }
    if out.is_empty() {
        "secret".to_string()
    } else {
        out
    }
}

fn build_secrets_block(names: &[String]) -> String {
    if names.is_empty() {
        return "  /**\n   * Project-specific secret keys from `.tako/secrets.json`.\n   *\n   * No secrets are currently configured for this project. After you add one,\n   * this interface is regenerated with typed readonly keys.\n   */\n  export interface TakoSecrets {}\n\n".to_string();
    }

    let example_name = names.first().map(String::as_str).unwrap_or("MY_SECRET");
    let mut out = format!(
        "  /**\n   * Project-specific secret keys from `.tako/secrets.json`.\n   *\n   * Values are injected by Tako at runtime and redacted during bulk serialization.\n   * App code reads individual values from `tako.secrets` imported from `tako.sh`.\n   *\n   * @example\n   * ```ts\n   * import {{ tako }} from \"tako.sh\";\n   *\n   * const {} = {};\n   * ```\n   */\n",
        secret_example_binding(example_name),
        ts_secret_accessor(example_name)
    );
    out.push_str("  export interface TakoSecrets {\n");
    for name in names {
        out.push_str(&format!(
            "    /** Secret `{name}`. Read it with `{}`. */\n",
            ts_secret_accessor(name)
        ));
        out.push_str(&format!(
            "    readonly {}: string;\n",
            ts_property_name(name)
        ));
    }
    out.push_str("  }\n\n");
    out
}

fn push_indented_block(out: &mut String, block: &str, spaces: usize) {
    let indent = " ".repeat(spaces);
    for line in block.lines() {
        out.push_str(&indent);
        out.push_str(line);
        out.push('\n');
    }
}

fn env_union(env_names: &[String]) -> String {
    let mut out = String::new();
    for (index, name) in env_names.iter().enumerate() {
        if index > 0 {
            out.push_str(" | ");
        }
        out.push('"');
        out.push_str(name);
        out.push('"');
    }
    out
}

fn example_env_name(env_names: &[String]) -> &str {
    env_names
        .iter()
        .find(|name| name.as_str() != "development" && name.as_str() != "production")
        .or_else(|| env_names.iter().find(|name| name.as_str() == "production"))
        .or_else(|| env_names.first())
        .map(String::as_str)
        .unwrap_or("development")
}

fn build_env_block(env_names: &[String]) -> String {
    let mut out = format!(
        "/**\n * Environments available through `tako.env`, `process.env.ENV`, and `import.meta.env.ENV`.\n *\n * Generated from `[envs.*]` in `tako.toml`, with `development` and `production` always included.\n *\n * @example\n * ```ts\n * import {{ tako }} from \"tako.sh\";\n *\n * if (tako.env === {:?}) {{\n *   tako.logger.info(\"running in the selected environment\");\n * }}\n * ```\n */\nexport type Env = ",
        example_env_name(env_names)
    );
    out.push_str(&env_union(env_names));
    out.push_str(";\n\n");
    out
}

fn build_type_registry_block(env_names: &[String]) -> String {
    let mut out = String::from(
        "  export interface TakoTypeRegistry {\n    /** Narrows the SDK's `Env` export to this project's configured environments. */\n    Env: ",
    );
    out.push_str(&env_union(env_names));
    out.push_str(";\n  }\n\n");
    out
}

fn build_global_augmentations() -> String {
    r#"/**
 * Tako-provided runtime environment variables available on `process.env` and `import.meta.env`.
 *
 * Values are strings because they come from the process environment.
 */
interface TakoRuntimeEnv {
  /** Current environment. Narrowed to `[envs.*]` declared in `tako.toml`. */
  readonly ENV: Env;
  /** Port Tako assigned to this app instance. */
  readonly PORT: string;
  /** Host/address Tako bound this app instance to. */
  readonly HOST: string;
  /** Build identifier injected by Tako at deploy time. `"dev"` under `tako dev`. */
  readonly TAKO_BUILD: string;
  /** Persistent app-owned data directory — writes survive restarts and deploys. */
  readonly TAKO_DATA_DIR: string;
}

declare global {
  namespace NodeJS {
    interface ProcessEnv extends TakoRuntimeEnv {}
  }
  interface ImportMetaEnv extends TakoRuntimeEnv {}
}
"#
    .to_string()
}

/// Build the full `tako.d.ts` content.
fn build_declarations(
    secret_names: &[String],
    env_names: &[String],
    channel_types: &str,
) -> String {
    let mut out = String::from(TAKO_DTS_HEADER);
    out.push_str(&build_env_block(env_names));
    out.push_str("declare module \"tako.sh\" {\n");
    out.push_str(&build_type_registry_block(env_names));
    out.push_str(&build_secrets_block(secret_names));
    if !channel_types.trim().is_empty() {
        push_indented_block(&mut out, channel_types, 2);
        out.push('\n');
    }
    out.push_str("}\n\n");
    out.push_str(&build_global_augmentations());
    out
}

/// Write `tako.d.ts` to the project's JavaScript app root.
pub fn write_tako_declarations(project_dir: &Path) -> std::io::Result<bool> {
    write_tako_declarations_for_adapter(project_dir, detect_build_adapter(project_dir))
}

/// Like [`write_tako_declarations`] but with an explicit adapter.
pub fn write_tako_declarations_for_adapter(
    project_dir: &Path,
    adapter: BuildAdapter,
) -> std::io::Result<bool> {
    let app_root = configured_js_app_root(project_dir);
    write_tako_declarations_for_adapter_and_app_root(project_dir, adapter, &app_root)
}

pub fn write_tako_declarations_for_adapter_and_app_root(
    project_dir: &Path,
    adapter: BuildAdapter,
    app_root: &str,
) -> std::io::Result<bool> {
    write_tako_declarations_for_adapter_with_bun(project_dir, adapter, app_root, OsStr::new("bun"))
}

fn write_tako_declarations_for_adapter_with_bun(
    project_dir: &Path,
    _adapter: BuildAdapter,
    app_root: &str,
    bun: &OsStr,
) -> std::io::Result<bool> {
    let secret_names = read_secret_names(project_dir);
    let env_names = read_env_names(project_dir);
    let channel_types = generate_channel_types_with_bun(project_dir, app_root, bun)?;
    let content = build_declarations(&secret_names, &env_names, &channel_types);
    let path = resolve_declaration_path(project_dir);
    if let Some(parent) = path.parent()
        && !parent.as_os_str().is_empty()
    {
        fs::create_dir_all(parent)?;
    }
    if let Ok(existing) = fs::read_to_string(&path)
        && existing == content
    {
        return Ok(false);
    }
    fs::write(&path, content)?;

    // Best-effort removal of the legacy runtime module so regenerated projects
    // do not keep importing stale generated values.
    for legacy in legacy_tako_gen_paths(project_dir, app_root) {
        if legacy.is_file() {
            let _ = fs::remove_file(&legacy);
        }
    }

    Ok(true)
}

fn generate_channel_types_with_bun(
    project_dir: &Path,
    app_root: &str,
    bun: &OsStr,
) -> std::io::Result<String> {
    let channels_dir = js_app_root_dir(project_dir, app_root).join("channels");
    if !channels_dir.is_dir() {
        return Ok(String::new());
    }

    let output = match channel_codegen_command(project_dir, &channels_dir, bun).output() {
        Ok(output) => output,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(String::new()),
        Err(err) => return Err(err),
    };
    if !output.status.success() {
        return Err(std::io::Error::other(format!(
            "channel generation failed: {}",
            String::from_utf8_lossy(&output.stderr).trim()
        )));
    }
    Ok(String::from_utf8_lossy(&output.stdout).to_string())
}

fn channel_codegen_command(project_dir: &Path, channels_dir: &Path, bun: &OsStr) -> Command {
    let repo_script = Path::new(env!("CARGO_MANIFEST_DIR"))
        .parent()
        .expect("tako crate lives under repo root")
        .join("sdk/javascript/bin/gen-channel-types.ts");
    if repo_script.is_file() {
        let mut command = Command::new(bun);
        command.arg(repo_script).arg(channels_dir);
        command.current_dir(project_dir);
        return command;
    }

    let mut command = Command::new(bun);
    command
        .arg("run")
        .arg("tako-sh-gen-channel-types")
        .arg(channels_dir);
    command.current_dir(project_dir);
    command
}

pub fn write_generated_files(project_dir: &Path) -> std::io::Result<JsGeneratedFilesResult> {
    write_generated_files_for_adapter(project_dir, detect_build_adapter(project_dir))
}

pub fn write_generated_files_for_adapter(
    project_dir: &Path,
    adapter: BuildAdapter,
) -> std::io::Result<JsGeneratedFilesResult> {
    let app_root = configured_js_app_root(project_dir);
    write_generated_files_for_adapter_and_app_root(project_dir, adapter, &app_root)
}

pub fn write_generated_files_for_adapter_and_app_root(
    project_dir: &Path,
    adapter: BuildAdapter,
    app_root: &str,
) -> std::io::Result<JsGeneratedFilesResult> {
    let wrote_scaffolds = ensure_js_definition_scaffolds(project_dir, app_root)?;
    let wrote_declarations =
        write_tako_declarations_for_adapter_and_app_root(project_dir, adapter, app_root)?;
    Ok(JsGeneratedFilesResult {
        wrote_declarations,
        wrote_scaffolds,
    })
}

pub(crate) fn js_app_root_dir(project_dir: &Path, app_root: &str) -> PathBuf {
    let trimmed = app_root.trim();
    if trimmed == "." || trimmed.is_empty() {
        project_dir.to_path_buf()
    } else {
        project_dir.join(trimmed)
    }
}

fn configured_js_app_root(project_dir: &Path) -> String {
    TakoToml::load_from_dir(project_dir)
        .map(|config| config.js_app_root().to_string())
        .unwrap_or_else(|_| DEFAULT_JS_APP_ROOT.to_string())
}

fn legacy_tako_gen_paths(project_dir: &Path, app_root: &str) -> Vec<PathBuf> {
    let mut paths: Vec<PathBuf> = generated_declaration_parent_dirs(project_dir)
        .into_iter()
        .map(|dir| dir.join("tako.gen.ts"))
        .collect();
    paths.push(js_app_root_dir(project_dir, app_root).join("tako.gen.ts"));
    paths.sort();
    paths.dedup();
    paths
}

#[derive(Clone, Copy)]
enum StubKind {
    Channel,
    Workflow,
}

impl StubKind {
    fn dir_name(self) -> &'static str {
        match self {
            Self::Channel => "channels",
            Self::Workflow => "workflows",
        }
    }

    fn helper_name(self) -> &'static str {
        match self {
            Self::Channel => "defineChannel",
            Self::Workflow => "defineWorkflow",
        }
    }

    fn default_export_line(self, stem: &str) -> String {
        match self {
            Self::Channel => {
                format!("export default defineChannel({{ name: {stem:?} }}).$messageTypes<{{}}>();")
            }
            Self::Workflow => {
                format!(
                    "export default defineWorkflow(\"{stem}\", {{ handler: async () => {{}} }});"
                )
            }
        }
    }
}

fn ensure_js_definition_scaffolds(project_dir: &Path, app_root: &str) -> std::io::Result<bool> {
    let mut wrote_any = false;
    let app_root_dir = js_app_root_dir(project_dir, app_root);
    for kind in [StubKind::Channel, StubKind::Workflow] {
        wrote_any |= ensure_dir_scaffolds(&app_root_dir.join(kind.dir_name()), kind)?;
    }
    Ok(wrote_any)
}

fn ensure_dir_scaffolds(dir: &Path, kind: StubKind) -> std::io::Result<bool> {
    if !dir.is_dir() {
        return Ok(false);
    }

    let mut module_files = Vec::new();
    for entry in fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        let Ok(file_type) = entry.file_type() else {
            continue;
        };
        if !file_type.is_file() {
            continue;
        }
        let Some(name) = path.file_name().and_then(|name| name.to_str()) else {
            continue;
        };
        if name.starts_with('.') || name.starts_with('_') {
            continue;
        }
        let Some(ext) = path.extension().and_then(|ext| ext.to_str()) else {
            continue;
        };
        let dot_ext = format!(".{ext}");
        if JS_MODULE_EXTS.contains(&dot_ext.as_str()) {
            module_files.push(path);
        }
    }
    module_files.sort();

    let mut wrote_any = false;
    if module_files.is_empty() {
        let stub_path = dir.join("demo.ts");
        let content = render_scaffold(kind, "demo", "");
        fs::write(stub_path, content)?;
        return Ok(true);
    }

    for path in module_files {
        let existing = fs::read_to_string(&path)?;
        let Some(stem) = path.file_stem().and_then(|stem| stem.to_str()) else {
            continue;
        };
        let Some(updated) = maybe_scaffold_source(kind, stem, &existing) else {
            continue;
        };
        if updated != existing {
            fs::write(&path, updated)?;
            wrote_any = true;
        }
    }

    Ok(wrote_any)
}

fn maybe_scaffold_source(kind: StubKind, stem: &str, existing: &str) -> Option<String> {
    if existing.contains("export default") {
        return None;
    }
    Some(render_scaffold(kind, stem, existing))
}

fn render_scaffold(kind: StubKind, stem: &str, existing: &str) -> String {
    let mut out = String::new();
    if !existing.contains(kind.helper_name()) {
        out.push_str(&format!(
            "import {{ {} }} from \"tako.sh\";\n\n",
            kind.helper_name()
        ));
    }
    if existing.trim().is_empty() {
        out.push_str(&kind.default_export_line(stem));
        out.push('\n');
        return out;
    }

    out.push_str(existing);
    if !existing.ends_with('\n') {
        out.push('\n');
    }
    out.push('\n');
    out.push_str(&kind.default_export_line(stem));
    out.push('\n');
    out
}

